1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	const COMPONENT_BLOCK_SIZE = 3;
16	const COMPONENT_BLOCK_PRICE = 60;
17	
18	interface Item {
19	  type: string;
20	  cursed?: boolean;
21	}
22	
23	interface QuoteStep {
24	  op: "quote";
25	  items: Item[];
26	}
27	
28	interface Scenario {
29	  customer: { yearsWithMHPCO: number };
30	  steps: QuoteStep[];
31	}
32	
33	export function runScenario(input: unknown): unknown {
34	  const scenario = input as Scenario;
35	  const results = scenario.steps.map((step) => {
36	    const countsByType: Record<string, number> = {};
37	    for (const item of step.items) {
38	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
39	    }
40	    let basePremium = 0;
41	    for (const [type, count] of Object.entries(countsByType)) {
42	      if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
43	        basePremium += COMPONENT_BLOCK_PRICE;
44	      } else {
45	        const perItem = BASE_PREMIUM[type] ?? 0;
46	        basePremium += perItem * count;
47	      }
48	    }
49	    let cursedSurcharge = 0;
50	    for (const item of step.items) {
51	      if (item.cursed) {
52	        cursedSurcharge += (BASE_PREMIUM[item.type] ?? 0) * CURSED_SURCHARGE_RATE;
53	      }
54	    }
55	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
56	    const rawPremium = basePremium + cursedSurcharge + firstInsurance + PROCESSING_FEE;
57	    const premium = Math.ceil(rawPremium);
58	    return { premium };
59	  });
60	  return { results };
61	}
